/**
 * Tests for posttool/tool-batch-observer (PostToolBatch, CC 2.1.208).
 *
 * P3-A3 contract: OBSERVER ONLY. Every input — empty, malformed, oversized —
 * must return { continue: true, suppressOutput: true }. Only sanitized,
 * capped tool NAMES are logged — never tool inputs or outputs.
 */

import { describe, test, expect, vi, beforeEach } from 'vitest';
import type { HookInput } from '../../types.js';

vi.mock('../../lib/common.js', async () => {
  const actual = await vi.importActual<typeof import('../../lib/common.js')>('../../lib/common.js');
  return { ...actual, logHook: vi.fn() };
});

import { toolBatchObserver } from '../../posttool/tool-batch-observer.js';
import { logHook } from '../../lib/common.js';

function expectSilentContinue(result: Record<string, unknown>): void {
  expect(result.continue).toBe(true);
  expect(result.suppressOutput).toBe(true);
  expect(result.decision).toBeUndefined();
  expect(result.systemMessage).toBeUndefined();
  expect(result.hookSpecificOutput).toBeUndefined();
}

describe('posttool/tool-batch-observer', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  test('empty input {} returns silent continue', async () => {
    const result = await toolBatchObserver({} as HookInput);
    expectSilentContinue(result as unknown as Record<string, unknown>);
  });

  test('absent/malformed batch fields return silent continue', async () => {
    const input = {
      hook_event: 'PostToolBatch',
      session_id: 'test-session',
      tool_name: '',
      tool_input: {},
      tool_calls: 'not-an-array', // wrong type — must be tolerated
      batch: { size: 3 }, // also wrong type
      results: [null, 42, 'string', {}, { tool_name: 7 }], // junk items
    } as unknown as HookInput;
    const result = await toolBatchObserver(input);
    expectSilentContinue(result as unknown as Record<string, unknown>);

    // Junk items degrade to '?' placeholders, never throw
    const line = vi.mocked(logHook).mock.calls[0]?.[1] ?? '';
    expect(line).toContain('size=5');
  });

  test('oversized batch returns silent continue and caps names logged', async () => {
    const batch = Array.from({ length: 10_000 }, (_, i) => ({
      tool_name: `Tool${'A'.repeat(500)}${i}`,
      tool_input: { payload: 'x'.repeat(1000) },
    }));
    const input = {
      hook_event: 'PostToolBatch',
      session_id: 'test-session',
      tool_name: '',
      tool_input: {},
      tool_calls: batch,
    } as unknown as HookInput;

    const result = await toolBatchObserver(input);
    expectSilentContinue(result as unknown as Record<string, unknown>);

    const line = vi.mocked(logHook).mock.calls[0]?.[1] ?? '';
    expect(line.length).toBeLessThan(512); // 8 names x 32 chars + framing
    expect(line).toContain('size=10000');
    expect(line).toContain('+9992'); // overflow marker, not 10k names
    expect(line).not.toContain('payload'); // tool inputs never logged
  });

  test('tool names are sanitized before logging', async () => {
    const input = {
      session_id: 'test-session',
      tool_name: '',
      tool_input: {},
      tool_calls: [{ tool_name: 'Bash; rm -rf /\n$(evil)' }, { name: 'Read' }],
    } as unknown as HookInput;
    const result = await toolBatchObserver(input);
    expectSilentContinue(result as unknown as Record<string, unknown>);

    const line = vi.mocked(logHook).mock.calls[0]?.[1] ?? '';
    expect(line).not.toContain(';');
    expect(line).not.toContain('$(');
    expect(line).not.toContain('\n');
    expect(line).toContain('Read');
  });
});
